#include<bits/stdc++.h>
using namespace std;
int h1,h2,f1,f2,m1,m2,mz1,mz2,c;
int main(){
    cin>>h1>>f1>>m1>>h2>>f2>>m2;
    mz1=h1*3600+f1*60+m1;
    mz2=h2*3600+f2*60+m2;
    if(mz2>mz1){
        mz1+=86400;
    }
    c=mz1-mz2;
    cout<<c/3600<<" ";
    c%=3600;
    cout<<c/60<<" ";
    c%=60;
    cout<<c;
}
